msg.topic = "tension";
msg.payload = msg.payload;
return msg;

msg.topic = "puissance_active";

let payload = msg.payload;

// Si c'est un Buffer → lire comme float
if (Buffer.isBuffer(payload)) {
    let buf = Buffer.from(payload);
    msg.payload = Number(buf.readFloatBE(0).toFixed(2));
}
// Si c'est un nombre → garder tel quel
else if (typeof payload === "number") {
    msg.payload = Number(payload.toFixed(2));
}
// Si c'est une string → convertir en nombre
else if (typeof payload === "string") {
    let val = parseFloat(payload);
    msg.payload = isNaN(val) ? 0 : Number(val.toFixed(2));
}
// Sinon → 0
else {
    msg.payload = 0;
}

return msg;

msg.topic = "courant";
msg.payload = msg.payload;
return msg;

msg.topic = "facteur_puissance";
msg.payload = msg.payload;
return msg;

msg.topic = "frequence";
msg.payload = msg.payload;
return msg;

msg.topic = "puissance_reactive";
msg.payload = msg.payload[0];
return msg;

msg.topic = "puissance_apparente";

let val = msg.payload;

// Si tableau → prendre le premier élément
if (Array.isArray(val)) val = val[0];

// Si Buffer → lire comme float
if (Buffer.isBuffer(val)) {
    val = Buffer.from(val).readFloatBE(0);
}

// Convertir en nombre
val = parseFloat(val);

// Si pas un nombre valide → mettre 0
msg.payload = isNaN(val) ? 0 : Number(val.toFixed(2));

return msg;

let data = flow.get("puissances") || {};

if (!msg.topic) return null;

data[msg.topic] = msg.payload;
flow.set("puissances", data);

// si les 3 valeurs sont reçues
if (data.puissance_active !== undefined &&
    data.puissance_reactive !== undefined &&
    data.puissance_apparente !== undefined) {

    let msg_out = { payload: data };
    flow.set("puissances", {}); // reset pour le prochain cycle
    return msg_out;
}

return null; // sinon attendre les autres valeurs

// msg.payload contient déjà toutes les puissances
let p = msg.payload;

msg.payload = {
    puissance_active: p.puissance_active,
    puissance_reactive: p.puissance_reactive,
    puissance_apparente: p.puissance_apparente
};

return msg;

// Stocker puissances dans global
global.set("puissance_active", msg.payload["puissance_active"]);
global.set("puissance_reactive", msg.payload["puissance_reactive"]);
global.set("puissance_apparente", msg.payload["puissance_apparente"]);
global.set("derniere_maj", Date.now());
return null;

msg.topic = "energie_active";

let buf = Buffer.from(msg.payload);
let haute = buf.readUInt32BE(0);
let basse = buf.readUInt32BE(4);
let valeur_brute = haute * Math.pow(2, 32) + basse;

// Adapter le diviseur selon la valeur affichée sur PM5300
let diviseur = 1000; // à ajuster
msg.payload = Number((valeur_brute / diviseur).toFixed(3));
return msg;

