function cleanVal(v) {
    let n = parseFloat(v);
    return isNaN(n) ? null : Number(n.toFixed(2));
}

// Lire toutes les valeurs
let tension_t    = cleanVal(global.get("tension"));
let courant_t    = cleanVal(global.get("courant"));
let frequence_t  = cleanVal(global.get("frequence"));
let fp_t        = cleanVal(global.get("facteur_puissance"));
let pa_t         = cleanVal(global.get("puissance_active"));
let pr_t         = cleanVal(global.get("puissance_reactive"));
let pap_t        = cleanVal(global.get("puissance_apparente"));
let ea_t         = cleanVal(global.get("energie_active"));
let er_t         = cleanVal(global.get("energie_reactive"));
let eap_t        = cleanVal(global.get("energie_apparente"));

// Si une valeur critique est null → ne pas envoyer
if (tension_t === null || courant_t === null || 
    frequence_t === null || ea_t === null) {
    node.warn("Donnees pas encore pretes — attente...");
    return null; // ← ne publie rien !
}

msg.payload = {
    "tension":             tension_t,
    "courant":             courant_t,
    "frequence":           frequence_t,
    "facteur_puissance":   fp_t ?? 0,
    "puissance_active":    pa_t ?? 0,
    "puissance_reactive":  pr_t ?? 0,
    "puissance_apparente": pap_t ?? 0,
    "energie_active":      ea_t,
    "energie_reactive":    er_t ?? 0,
    "energie_apparente":   eap_t ?? 0,
    "timestamp":           new Date().toISOString(),
    "statut":              (Date.now() - (global.get("derniere_maj") || 0)) < 360000 
                             ? "connecte" : "deconnecte"
};

return msg;

